{
  "sentences": [
    {
      "text": "我要一個塑膠袋。",
      "pinyin": "Wǒ yào yī ge sùjiāodài.",
      "pinyin_numeric": "wo3 yao4 yi1 ge4 su4jiao1dai4.",
      "translation_en": "I want one plastic bag.",
      "translation_ko": "비닐봉지 하나 주세요."
    },
    {
      "text": "這個便當需要加熱嗎？",
      "pinyin": "Zhège biàndāng xūyào jiārè ma?",
      "pinyin_numeric": "zhe4ge5 bian4dang1 xu1yao4 jia1re4 ma0?",
      "translation_en": "Does this bento need to be heated?",
      "translation_ko": "이 도시락은 데워야 하나요?"
    },
    {
      "text": "我要用信用卡付款。",
      "pinyin": "Wǒ yào yòng xìnyòngkǎ fùkuǎn.",
      "pinyin_numeric": "wo3 yao4 yong4 xin4yong4ka3 fu4kuan3.",
      "translation_en": "I want to pay by credit card.",
      "translation_ko": "신용카드로 결제할게요."
    },
    {
      "text": "請幫我掃描條碼。",
      "pinyin": "Qǐng bāng wǒ sǎomiáo tiáomǎ.",
      "pinyin_numeric": "qing3 bang1 wo3 sao3miao2 tiao2ma3.",
      "translation_en": "Please scan the barcode for me.",
      "translation_ko": "바코드를 스캔해 주세요."
    },
    {
      "text": "我要買一包餅乾和兩瓶礦泉水。",
      "pinyin": "Wǒ yào mǎi yī bāo bǐnggān hé liǎng píng kuàngquánshuǐ.",
      "pinyin_numeric": "wo3 yao4 mai3 yi1 bao1 bing3gan1 he2 liang3 ping2 kuang4quan2shui3.",
      "translation_en": "I want to buy one pack of cookies and two bottles of mineral water.",
      "translation_ko": "과자 한 봉지와 생수 두 병을 살게요."
    },
    {
      "text": "這個飯糰有特價嗎？",
      "pinyin": "Zhège fàntuán yǒu tèjià ma?",
      "pinyin_numeric": "zhe4ge5 fan4tuan2 you3 te4jia4 ma0?",
      "translation_en": "Is this rice ball on sale?",
      "translation_ko": "이 주먹밥은 특가인가요?"
    },
    {
      "text": "我要買一送一的茶葉蛋。",
      "pinyin": "Wǒ yào mǎi yī sòng yī de cháyèdàn.",
      "pinyin_numeric": "wo3 yao4 mai3 yi1 song4 yi1 de5 cha2ye4dan4.",
      "translation_en": "I want to buy the buy-one-get-one-free tea eggs.",
      "translation_ko": "하나 사면 하나 더 주는 차(茶)알을 살게요."
    },
    {
      "text": "總共多少錢？",
      "pinyin": "Zǒnggòng duōshao qián?",
      "pinyin_numeric": "zong3gong4 duo1shao3 qian2?",
      "translation_en": "How much is the total?",
      "translation_ko": "총 얼마인가요?"
    },
    {
      "text": "我要用載具存發票。",
      "pinyin": "Wǒ yào yòng zàijù cún fāpiào.",
      "pinyin_numeric": "wo3 yao4 yong4 zai4ju4 cun2 fa1piao4.",
      "translation_en": "I want to store the receipt using the carrier (invoice carrier).",
      "translation_ko": "영수증을 (전자) 수단에 저장할게요."
    },
    {
      "text": "請給我兩張明細。",
      "pinyin": "Qǐng gěi wǒ liǎng zhāng míngxì.",
      "pinyin_numeric": "qing3 gei3 wo3 liang3 zhang1 ming2xi4.",
      "translation_en": "Please give me two copies of the receipt details.",
      "translation_ko": "명세서 두 장 주세요."
    }
  ]
}
